// src/services/communityQuestService.ts
import { redis } from '../redis';
import { db } from '../db';
import { io } from '../socket';
export async function contributeToCommunityQuest(playerId: string, questCode: string, amount: number) {
  const newProgress = await redis.incrby(`community:${questCode}:progress`, amount);
  await db.none('INSERT INTO player_community_contribution(player_id, quest_id, contribution) VALUES ($1, $2, $3) ON CONFLICT (player_id, quest_id) DO UPDATE SET contribution = player_community_contribution.contribution + $3', [playerId, questCode, amount]);
  io.emit('community_progress', { questCode, progress: newProgress });
  const quest = await db.one('SELECT * FROM community_quests WHERE code=$1', [questCode]);
  for (const tier of quest.tiers) {
    if (newProgress >= tier.threshold && newProgress - amount < tier.threshold) {
      await distributeTierRewards(questCode, tier);
    }
  }
}
async function distributeTierRewards(questCode: string, tier: any) {
  const contributors = await db.any('SELECT player_id FROM player_community_contribution WHERE quest_id=$1 AND contribution > 0', [questCode]);
  for (const c of contributors) {
    await db.none('INSERT INTO player_pending_rewards(player_id, reward_payload, source) VALUES ($1, $2, $3)', [c.player_id, JSON.stringify(tier.reward), `community:${questCode}:tier_${tier.threshold}`]);
  }
  io.emit('community_tier_unlocked', { questCode, tier });
}

