// src/components/CommunityQuestBanner.tsx
import useSWR from 'swr';
import { useEffect, useState } from 'react';
import { useSocket } from '../hooks/useSocket';
import { motion } from 'framer-motion';
export function CommunityQuestBanner({ questCode }: any) {
  const { data, mutate } = useSWR(`/api/community-quest/${questCode}`, u => fetch(u).then(r => r.json()));
  const socket = useSocket();
  const [liveProgress, setLiveProgress] = useState<number | null>(null);
  useEffect(() => {
    socket.on('community_progress', (msg: any) => { if (msg.questCode === questCode) setLiveProgress(msg.progress); });
    return () => { socket.off('community_progress'); };
  }, [socket, questCode]);
  if (!data) return null;
  const progress = liveProgress ?? data.current_progress;
  const pct = Math.min(100, (progress / data.target) * 100);
  return (
    <div className='p-6 rounded-2xl bg-gradient-to-br from-rose-900 to-orange-900 text-white'>
      <div className='text-xs uppercase tracking-widest text-rose-300'>Community Major Order</div>
