// src/services/choiceDropService.ts
import { db } from '../db';
import { mulberry32, hashSeed } from '../lib/prng';
export async function generateChoiceDrop(playerId: string, runId: string, dropSeed: string) {
  const rand = mulberry32(hashSeed(`${runId}:${dropSeed}`));
  const recentSkips = await db.any('SELECT dropped_item FROM player_drop_history WHERE player_id=$1 AND run_id=$2 AND picked=false ORDER BY drop_num DESC LIMIT 5', [playerId, runId]);
  const bannedSet = new Set(recentSkips.map(r => r.dropped_item));
  const pool = await db.any('SELECT * FROM item_pool');
  const weighted = pool.map(it => ({ ...it, w: it.weight * (bannedSet.has(it.code) ? 0.5 : 1) }));
  const choices: any[] = [];
  for (let i = 0; i < 3; i++) {
    const remaining = weighted.filter(w => !choices.find(c => c.code === w.code));
    const total = remaining.reduce((s, x) => s + x.w, 0);
    let r = rand() * total;
    for (const item of remaining) { r -= item.w; if (r <= 0) { choices.push(item); break; } }
  }
  return choices;
}
export async function pickFromDrop(playerId: string, runId: string, dropNum: number, pickedCode: string, allChoices: string[]) {
  return db.tx(async tx => {
    for (const code of allChoices) {
      await tx.none('INSERT INTO player_drop_history(player_id, dropped_item, picked, drop_num, run_id) VALUES ($1, $2, $3, $4, $5)', [playerId, code, code === pickedCode, dropNum, runId]);
    }
    await tx.none('INSERT INTO run_inventory(run_id, item_code) VALUES ($1, $2)', [runId, pickedCode]);
  });
}

