// src/services/seasonalAchievementService.ts
import { db } from '../db';
export async function unlockSeasonalAchievement(playerId: string, achievementId: string) {
  return db.tx(async tx => {
    const ach = await tx.one('SELECT * FROM seasonal_achievements WHERE id=$1', [achievementId]);
    const season = await tx.one('SELECT * FROM seasons WHERE id=$1', [ach.season_id]);
    const now = new Date();
    const inOriginalWindow = now >= season.starts_at && now <= season.ends_at;
    const inTimeCapsule = await tx.oneOrNone('SELECT 1 FROM time_capsule_windows WHERE includes_season=$1 AND starts_at <= NOW() AND ends_at >= NOW()', [ach.season_id]);
    if (!inOriginalWindow && !inTimeCapsule) throw new Error('not_currently_available');
    await tx.none('INSERT INTO player_seasonal_unlock(player_id, achievement_id, unlocked_at, was_during_original_season) VALUES ($1, $2, NOW(), $3) ON CONFLICT DO NOTHING', [playerId, achievementId, inOriginalWindow]);
  });
}
export async function openTimeCapsule(includedSeasons: number[]) {
  await db.none('INSERT INTO time_capsule_windows(includes_season, starts_at, ends_at) VALUES ($1, NOW(), NOW() + INTERVAL '14 days')', [includedSeasons]);
}

