// src/services/multiCategoryDailyService.ts
import { db } from '../db';
export async function submitMultiCategorySolve(playerId: string, date: string, category: string, timeMs: number) {
  return db.tx(async tx => {
    await tx.none('INSERT INTO player_daily_solve(player_id, date, category, time_ms) VALUES ($1, $2, $3, $4) ON CONFLICT DO NOTHING', [playerId, date, category, timeMs]);
    await tx.none(`INSERT INTO player_category_stats(player_id, category, total_solves, best_time, avg_time) VALUES ($1, $2, 1, $3, $3) ON CONFLICT (player_id, category) DO UPDATE SET total_solves = player_category_stats.total_solves + 1, best_time = LEAST(player_category_stats.best_time, $3), avg_time = (player_category_stats.avg_time * player_category_stats.total_solves + $3) / (player_category_stats.total_solves + 1)`, [playerId, category, timeMs]);
    const streak = await tx.one('SELECT current_streak, longest_streak, last_solve_date FROM player_global_streak WHERE player_id=$1', [playerId]);
    const lastDate = streak.last_solve_date;
    let newStreak = streak.current_streak;
    if (lastDate === date) { /* same day, no change */ }
    else if (lastDate === new Date(new Date(date).getTime() - 86400000).toISOString().slice(0, 10)) newStreak += 1;
    else newStreak = 1;
    await tx.none('UPDATE player_global_streak SET current_streak=$1, longest_streak=GREATEST(longest_streak, $1), last_solve_date=$2 WHERE player_id=$3', [newStreak, date, playerId]);
  });
}

