import { db } from '../db';
import { sendPush } from './pushDispatcher';
export async function notifyFollowersOfEvent(playerId: string, eventType: string, eventData: any) {
  const followers = await db.any('SELECT viewer_id FROM player_follows WHERE player_id=$1', [playerId]);
  for (const f of followers) {
    const recentSamePlayer = await db.oneOrNone('SELECT 1 FROM follow_notifications_log WHERE viewer_id=$1 AND player_id=$2 AND sent_at > NOW() - INTERVAL '1 hour'', [f.viewer_id, playerId]);
    if (recentSamePlayer) continue;
    const totalRecent = await db.one('SELECT COUNT(*) FROM follow_notifications_log WHERE viewer_id=$1 AND sent_at > NOW() - INTERVAL '1 hour'', [f.viewer_id]);
    if (Number(totalRecent.count) >= 5) continue;
    await sendPush(f.viewer_id, { title: 'Player you follow', body: `${eventData.player_name} ${eventType === 'match_starting' ? 'starts a match soon' : 'advanced in bracket'}`, deep_link: `/tournament/${eventData.tournament_id}` });
    await db.none('INSERT INTO follow_notifications_log(viewer_id, player_id, type) VALUES ($1, $2, $3)', [f.viewer_id, playerId, eventType]);
  }
}

