// src/services/giftingService.ts
import { db } from '../db';
export async function sendGift(senderId: string, recipientId: string, payload: any, useStipend = false) {
  return db.tx(async tx => {
    const today = new Date().toISOString().slice(0, 10);
    const counts = await tx.oneOrNone('SELECT * FROM daily_gift_count WHERE player_id=$1 AND date=$2 FOR UPDATE', [senderId, today]);
    if (counts && counts.sent >= 5) throw new Error('daily_send_cap');
    if (useStipend && counts && counts.stipend_used >= 3) throw new Error('stipend_exhausted');
    const giftValue = payload.value || 0;
    if (giftValue > 200) throw new Error('gift_value_exceeds_cap');
    if (!useStipend) await applyCurrencyChange({ playerId: senderId, currency: 'soft', delta: -giftValue, reason: 'gift_sent', referenceId: recipientId, idempotencyKey: `gift:${senderId}:${recipientId}:${Date.now()}` });
    await tx.none('INSERT INTO gifts(sender_id, recipient_id, item_payload) VALUES ($1, $2, $3)', [senderId, recipientId, JSON.stringify(payload)]);
    await tx.none('INSERT INTO daily_gift_count(player_id, date, sent, stipend_used) VALUES ($1, $2, 1, $3) ON CONFLICT (player_id, date) DO UPDATE SET sent = daily_gift_count.sent + 1, stipend_used = daily_gift_count.stipend_used + $3', [senderId, today, useStipend ? 1 : 0]);
    const recentToSame = await tx.one('SELECT COUNT(*) FROM gifts WHERE sender_id=$1 AND recipient_id=$2 AND sent_at > NOW() - INTERVAL '30 days'', [senderId, recipientId]);
    if (Number(recentToSame.count) > 50) await tx.none('INSERT INTO rmt_review_queue(sender_id, recipient_id, reason) VALUES ($1, $2, $3) ON CONFLICT DO NOTHING', [senderId, recipientId, 'high_volume_repeat']);
  });
}

