// src/services/playerStatsService.ts
import { db } from '../db';
export async function queryPlayers(filters: any, sort: any[], offset: number, limit: number) {
  let where = '1=1';
  const params: any[] = [];
  if (filters.position) { params.push(filters.position); where += ` AND position = $${params.length}`; }
  if (filters.age_min) { params.push(filters.age_min); where += ` AND age >= $${params.length}`; }
  if (filters.age_max) { params.push(filters.age_max); where += ` AND age <= $${params.length}`; }
  if (filters.value_min) { params.push(filters.value_min); where += ` AND value >= $${params.length}`; }
  const orderBy = sort.map(s => `${s.col} ${s.dir.toUpperCase()}`).join(', ');
  params.push(limit); params.push(offset);
  const rows = await db.any(`SELECT * FROM player_attributes WHERE ${where} ORDER BY ${orderBy || 'id'} LIMIT $${params.length - 1} OFFSET $${params.length}`, params);
  return rows;
}
export async function comparePlayers(playerIds: string[]) {
  return db.any('SELECT * FROM player_attributes WHERE player_id = ANY($1)', [playerIds]);
}

