// src/services/coopRunMatchmaker.ts
import { redis } from '../redis';
import { db } from '../db';
export async function queueCoopRun(playerId: string, tier: number, partyId: string | null) {
  await redis.zadd(`coop_run:${tier}`, Date.now(), `${playerId}:${partyId || playerId}`);
  for (let i = 0; i < 30; i++) {
    const candidates = await redis.zrange(`coop_run:${tier}`, 0, -1);
    if (candidates.length >= 4) {
      const lobby = candidates.slice(0, 4).map(c => c.split(':')[0]);
      for (const c of candidates.slice(0, 4)) await redis.zrem(`coop_run:${tier}`, c);
      const seed = Math.floor(Math.random() * 2 ** 32);
      const room = await db.one('INSERT INTO coop_lobbies(tier, seed, members) VALUES ($1, $2, $3) RETURNING *', [tier, seed, lobby]);
      return room;
    }
    await new Promise(r => setTimeout(r, 1000));
  }
  await redis.zrem(`coop_run:${tier}`, `${playerId}:${partyId || playerId}`);
  return { timedOut: true };
}

