import { db } from '../db';
export async function submitPrediction(viewerId: string, matchId: string, predictedWinner: string) {
  return db.tx(async tx => {
    const match = await tx.one('SELECT starts_at FROM tournament_matches WHERE id=$1', [matchId]);
    if (new Date(match.starts_at) < new Date()) throw new Error('match_already_started');
    await tx.none('INSERT INTO viewer_predictions(viewer_id, match_id, predicted_winner) VALUES ($1, $2, $3) ON CONFLICT (viewer_id, match_id) DO UPDATE SET predicted_winner = $3', [viewerId, matchId, predictedWinner]);
  });
}
export async function resolvePrediction(matchId: string, actualWinner: string) {
  return db.tx(async tx => {
    const match = await tx.one('SELECT player_a_rating, player_b_rating, player_a, player_b FROM tournament_matches WHERE id=$1', [matchId]);
    const underdog = match.player_a_rating < match.player_b_rating ? match.player_a : match.player_b;
    const upset = actualWinner === underdog;
    const skillDiff = Math.abs(match.player_a_rating - match.player_b_rating);
    const bonus = upset ? Math.log2(skillDiff + 1) : 0;
    const predictions = await tx.any('SELECT * FROM viewer_predictions WHERE match_id=$1', [matchId]);
    for (const p of predictions) {
      const correct = p.predicted_winner === actualWinner;
      const points = correct ? 10 + bonus : 0;
      await tx.none('UPDATE viewer_predictions SET points_earned=$1, resolved=true WHERE viewer_id=$2 AND match_id=$3', [points, p.viewer_id, matchId]);
      await tx.none('UPDATE viewer_total_points SET points = points + $1 WHERE viewer_id=$2', [points, p.viewer_id]);
    }
  });
}

