// src/services/shardManager.ts
import { db } from '../db';
import { redis } from '../redis';
export async function assignShard(playerId: string, region: string) {
  const friends = await db.any('SELECT CASE WHEN player_a=$1 THEN player_b ELSE player_a END AS fid FROM friendships WHERE player_a=$1 OR player_b=$1', [playerId]);
  for (const f of friends) {
    const fShard = await redis.get(`player_shard:${f.fid}`);
    if (fShard) {
      const pop = await redis.get(`shard_pop:${fShard}`);
      if (Number(pop) < 500) { await joinShard(playerId, fShard); return fShard; }
    }
  }
  const shards = await db.any('SELECT * FROM shards WHERE region=$1 ORDER BY current_population', [region]);
  for (const s of shards) { if (s.current_population < 400) { await joinShard(playerId, s.id); return s.id; } }
  const newShard = await db.one('INSERT INTO shards(region, current_population, capacity) VALUES ($1, 1, 500) RETURNING id', [region]);
  await joinShard(playerId, newShard.id);
  return newShard.id;
}
async function joinShard(playerId: string, shardId: string) {
  await redis.set(`player_shard:${playerId}`, shardId);
  await redis.incr(`shard_pop:${shardId}`);
}

