// src/services/weaponGenerator.ts
import { mulberry32, hashSeed } from '../lib/prng';
import { db } from '../db';
export async function rollWeapon(playerId: string, seed: string, rarity: string) {
  const rand = mulberry32(hashSeed(`${playerId}:${seed}`));
  const bases = await db.any('SELECT * FROM weapon_bases');
  const manufacturers = await db.any('SELECT * FROM manufacturers');
  const base = bases[Math.floor(rand() * bases.length)];
  const manu = manufacturers[Math.floor(rand() * manufacturers.length)];
  const rolledStats: any = {};
  for (const [stat, range] of Object.entries<any>(base.base_stats)) {
    const mult = manu.bias[stat] || 1.0;
    const raw = range.min + rand() * (range.max - range.min);
    rolledStats[stat] = Math.floor(raw * mult * (rarity === 'rare' ? 1.5 : 1.0));
  }
  const prefixes = ['Cursed', 'Eternal', 'Burning', 'Lucky'];
  const suffixes = ['of Doom', 'of Death', 'of Burning'];
  const prefix = rand() < 0.5 ? prefixes[Math.floor(rand() * prefixes.length)] : null;
  const suffix = rand() < 0.5 ? suffixes[Math.floor(rand() * suffixes.length)] : null;
  const weapon = await db.one('INSERT INTO dropped_weapons(owner_id, base_id, manufacturer_id, rolled_stats, prefix, suffix) VALUES ($1, $2, $3, $4, $5, $6) RETURNING *', [playerId, base.id, manu.id, JSON.stringify(rolledStats), prefix, suffix]);
  return { ...weapon, base_name: base.name, manufacturer_name: manu.name, manufacturer_color: manu.color };
}

