import { useEffect, useState, useRef } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import * as THREE from 'three';
function Note({ targetTime, audioStart, onHit, calibration }: any) {
  const meshRef = useRef<THREE.Mesh>(null);
  useFrame((state) => {
    const audioNow = (state.clock.elapsedTime * 1000) - audioStart - calibration;
    const remaining = targetTime - audioNow;
    if (meshRef.current) meshRef.current.position.z = remaining / 200;
    if (Math.abs(remaining) < 50 && (window as any)._lastHitInput && Math.abs((window as any)._lastHitInput - Date.now()) < 50) {
      onHit(remaining);
      (window as any)._lastHitInput = 0;
    }
  });
  return <mesh ref={meshRef}><boxGeometry args={[0.5, 0.5, 0.1]} /><meshBasicMaterial color='#06b6d4' /></mesh>;
}
export function RhythmGame({ beatmap }: any) {
  const audioRef = useRef<HTMLAudioElement>(null);
  const [audioStart, setAudioStart] = useState(0);
  const [calibration, setCalibration] = useState(0);
  const [score, setScore] = useState(0);
  const [feedback, setFeedback] = useState<string | null>(null);
  useEffect(() => {
    const onKey = () => { (window as any)._lastHitInput = Date.now(); };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, []);
  const onHit = (delta: number) => {
    const abs = Math.abs(delta);
    if (abs < 50) { setScore(s => s + 100); setFeedback('PERFECT'); }
    else if (abs < 100) { setScore(s => s + 50); setFeedback('Good'); }
    setTimeout(() => setFeedback(null), 500);
  };
  return (
    <div className='relative w-full h-screen bg-slate-950'>
      <Canvas><ambientLight />{beatmap.notes.map((n: any, i: number) => <Note key={i} targetTime={n.time} audioStart={audioStart} onHit={onHit} calibration={calibration} />)}</Canvas>
      <audio ref={audioRef} onPlay={() => setAudioStart(performance.now())} src={beatmap.audio_url} />
      <div className='absolute top-4 left-4 text-white text-2xl font-bold'>{score}</div>
      {feedback && <div className='absolute inset-0 flex items-center justify-center pointer-events-none'><div className={`text-6xl font-black ${feedback === 'PERFECT' ? 'text-yellow-300' : 'text-cyan-400'}`}>{feedback}</div></div>}
    </div>
  );
}

