import { db } from '../db';
export async function withdrawFromBank(playerId: string, guildId: string, tabIdx: number, itemCode: string, quantity: number) {
  return db.tx(async tx => {
    const member = await tx.one('SELECT role FROM guild_members WHERE guild_id=$1 AND player_id=$2', [guildId, playerId]);
    const perm = await tx.oneOrNone('SELECT daily_withdrawal_limit FROM tab_permissions WHERE guild_id=$1 AND tab_idx=$2 AND role=$3', [guildId, tabIdx, member.role]);
    if (!perm) throw new Error('no_access');
    const today = new Date().toISOString().slice(0, 10);
    const usedToday = await tx.one(`SELECT COALESCE(SUM((item_payload->>'value')::numeric), 0) AS used FROM bank_audit WHERE guild_id=$1 AND actor=$2 AND tab_idx=$3 AND action='withdraw' AND ts > $4`, [guildId, playerId, tabIdx, today]);
    const itemValue = await tx.one('SELECT value FROM items WHERE code=$1', [itemCode]);
    if (Number(usedToday.used) + itemValue.value * quantity > perm.daily_withdrawal_limit) throw new Error('daily_limit_exceeded');
    const tab = await tx.one('SELECT items FROM guild_bank_tabs WHERE guild_id=$1 AND tab_idx=$2 FOR UPDATE', [guildId, tabIdx]);
    const newItems = { ...tab.items };
    if ((newItems[itemCode] || 0) < quantity) throw new Error('insufficient_stock');
    newItems[itemCode] -= quantity;
    await tx.none('UPDATE guild_bank_tabs SET items=$1 WHERE guild_id=$2 AND tab_idx=$3', [JSON.stringify(newItems), guildId, tabIdx]);
    await tx.none('INSERT INTO bank_audit(guild_id, actor, action, item_payload, tab_idx) VALUES ($1, $2, $3, $4, $5)', [guildId, playerId, 'withdraw', JSON.stringify({ itemCode, quantity, value: itemValue.value * quantity }), tabIdx]);
    await tx.none('INSERT INTO player_inventory(player_id, item_code, quantity) VALUES ($1, $2, $3) ON CONFLICT (player_id, item_code) DO UPDATE SET quantity = player_inventory.quantity + $3', [playerId, itemCode, quantity]);
  });
}

