// src/jobs/copyPasteDetector.ts
import { db } from '../db';
export function analyzeReplay(replay: any[]): { score: number; flagged: boolean } {
  const deltas: number[] = [];
  for (let i = 1; i < replay.length; i++) deltas.push(replay[i].t - replay[i - 1].t);
  const mean = deltas.reduce((s, x) => s + x, 0) / deltas.length;
  const std = Math.sqrt(deltas.reduce((s, x) => s + (x - mean) ** 2, 0) / deltas.length);
  const cv = std / mean;
  const uniqueRatio = new Set(replay.map(r => r.action)).size / replay.length;
  let score = 0;
  if (cv < 0.2) score += 3;
  if (uniqueRatio > 0.95 && replay.length > 20) score += 2;
  return { score, flagged: score >= 4 };
}

