import { db } from '../db';
export async function processWin(playerId: string, mode: string, baseReward: number) {
  return db.tx(async tx => {
    const today = new Date().toISOString().slice(0, 10);
    const state = await tx.oneOrNone('SELECT mode_flags FROM player_daily_first_wins WHERE player_id=$1 AND date=$2 FOR UPDATE', [playerId, today]);
    const flags = state?.mode_flags || {};
    const wasFirstWin = !flags[mode];
    if (wasFirstWin) {
      flags[mode] = true;
      await tx.none('INSERT INTO player_daily_first_wins(player_id, date, mode_flags) VALUES ($1, $2, $3) ON CONFLICT (player_id, date) DO UPDATE SET mode_flags=$3', [playerId, today, JSON.stringify(flags)]);
      const reward = baseReward * 2;
      const allModes = ['arena', 'campaign', 'raid', 'pvp'];
      if (allModes.every(m => flags[m])) {
        const bonus = baseReward * 3;
        return { reward: reward + bonus, allModeBonus: true };
      }
      return { reward, firstWin: true };
    }
    return { reward: baseReward };
  });
}

