// src/services/lobbyBackfillService.ts
import { redis } from '../redis';
import { db } from '../db';
import { io } from '../socket';
export async function backfillLobby(lobbyId: string) {
  const lobby = await db.one('SELECT * FROM lobbies WHERE id=$1', [lobbyId]);
  if (lobby.current_players.length >= lobby.target_size) return;
  const needed = lobby.target_size - lobby.current_players.length;
  let skillWindow = 100;
  while (skillWindow < 500) {
    const candidates = await redis.zrangebyscore(`mm:${lobby.mode}`, lobby.skill_target - skillWindow, lobby.skill_target + skillWindow, 'LIMIT', 0, needed);
    if (candidates.length >= needed) {
      for (const c of candidates) { await redis.zrem(`mm:${lobby.mode}`, c); await db.none('UPDATE lobbies SET current_players = array_append(current_players, $1) WHERE id=$2', [c, lobbyId]); io.to(`lobby:${lobbyId}`).emit('player_joined', { playerId: c }); }
      return;
    }
    skillWindow += 100;
    await new Promise(r => setTimeout(r, 2000));
  }
}

