  await db.none('INSERT INTO match_mvp_votes(voter_id, match_id, voted_for) VALUES ($1, $2, $3) ON CONFLICT (voter_id, match_id) DO UPDATE SET voted_for=$3', [voterId, matchId, votedFor]);
