export async function calculateMvpAwards(matchId: string) {
  return db.tx(async tx => {
    const stats = await tx.any(`SELECT player_id, kills * 2 + assists * 1.5 + objective_score AS mvp_score FROM match_player_stats WHERE match_id=$1 ORDER BY mvp_score DESC`, [matchId]);
    const autoMvp = stats[0];
    const votes = await tx.any('SELECT voted_for, COUNT(*) AS vote_count FROM match_mvp_votes WHERE match_id=$1 GROUP BY voted_for ORDER BY vote_count DESC', [matchId]);
    const communityMvp = votes[0];
    await tx.none('INSERT INTO match_awards(match_id, player_id, award_type) VALUES ($1, $2, $3)', [matchId, autoMvp.player_id, 'auto_mvp']);
    if (communityMvp) await tx.none('INSERT INTO match_awards(match_id, player_id, award_type) VALUES ($1, $2, $3)', [matchId, communityMvp.voted_for, 'community_mvp']);
  });
}

