// src/services/ambientEventService.ts
import { db } from '../db';
import { mulberry32, hashSeed } from '../lib/prng';
export async function maybeSpawnEvent(playerId: string, biome: string, timeOfDay: string) {
  const last30 = await db.any('SELECT event_code FROM player_event_history WHERE player_id=$1 AND spawned_at > NOW() - INTERVAL '30 minutes'', [playerId]);
  const onCooldown = new Set(last30.map(e => e.event_code));
  const eligible = await db.any('SELECT * FROM world_events WHERE $1 = ANY(biome_filter) AND $2 = ANY(time_filter)', [biome, timeOfDay]);
  const available = eligible.filter(e => !onCooldown.has(e.code));
  if (available.length === 0) return null;
  const rand = mulberry32(hashSeed(`${playerId}:${Date.now()}`));
  if (rand() > 0.10) return null;
  const total = available.reduce((s, e) => s + e.weight, 0);
  let r = rand() * total;
  let chosen: any = null;
  for (const e of available) { r -= e.weight; if (r <= 0) { chosen = e; break; } }
  if (!chosen) return null;
  await db.none('INSERT INTO player_event_history(player_id, event_code) VALUES ($1, $2)', [playerId, chosen.code]);
  return chosen;
}

