// src/services/modelUploadService.ts
import { db } from '../db';
import { GLTFLoader } from 'three/examples/jsm/loaders/GLTFLoader';
import { s3 } from '../aws';
import fs from 'fs';
export async function uploadModel(uploaderId: string, buffer: Buffer) {
  const loader = new GLTFLoader();
  const parsed: any = await new Promise((res, rej) => loader.parse(buffer, '', res as any, rej));
  let totalTris = 0;
  parsed.scene.traverse((obj: any) => { if (obj.geometry) totalTris += obj.geometry.attributes.position.count / 3; });
  if (totalTris > 100000) throw new Error('polygon_count_exceeded');
  for (const tex of parsed.parser.json.images || []) {
    if (tex.width > 4096 || tex.height > 4096) throw new Error('texture_too_large');
  }
  if (parsed.parser.json.extensions) {
    const allowed = ['KHR_materials_pbrSpecularGlossiness', 'KHR_texture_basisu'];
    for (const ext of Object.keys(parsed.parser.json.extensions)) if (!allowed.includes(ext)) throw new Error('disallowed_extension');
  }
  const key = `models/${uploaderId}/${Date.now()}.glb`;
  await s3.putObject({ Bucket: 'models', Key: key, Body: buffer }).promise();
  return db.one('INSERT INTO user_models(uploader, file_url, polys, validated) VALUES ($1, $2, $3, true) RETURNING *', [uploaderId, key, totalTris]);
}

