// src/services/crossGamePresenceService.ts
import { redis } from '../redis';
import { db } from '../db';
import { io } from '../socket';
export async function setRichPresence(playerId: string, gameId: string, richText: string, joinable: boolean) {
  const token = joinable ? Math.random().toString(36).slice(2) : null;
  await redis.hset(`presence:${playerId}`, { game_id: gameId, rich_text: richText, joinable: joinable.toString(), joinable_token: token || '', updated_at: Date.now().toString() });
  await redis.expire(`presence:${playerId}`, 3600);
  const friends = await db.any('SELECT CASE WHEN player_a=$1 THEN player_b ELSE player_a END AS fid FROM friendships WHERE player_a=$1 OR player_b=$1', [playerId]);
  for (const f of friends) io.to(`player:${f.fid}`).emit('friend_presence_changed', { playerId });
}
export async function getFriendPresence(viewerId: string) {
  const friends = await db.any('SELECT CASE WHEN player_a=$1 THEN player_b ELSE player_a END AS fid FROM friendships WHERE player_a=$1 OR player_b=$1', [viewerId]);
  const out: any[] = [];
  for (const f of friends) {
    const presence = await redis.hgetall(`presence:${f.fid}`);
    if (presence.game_id) {
      const game = await db.one('SELECT id, name, art_url, deep_link_template FROM games WHERE id=$1', [presence.game_id]);
      out.push({ player_id: f.fid, game_name: game.name, game_art: game.art_url, rich_text: presence.rich_text, joinable: presence.joinable === 'true', deep_link: presence.joinable === 'true' ? game.deep_link_template.replace('{token}', presence.joinable_token) : null });
    }
  }
  return out;
}

